using System;
using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.SceneManagement;
using UnityEngine.UI;

/// <summary>
/// Menu de Save (Etapa de Menu de Save): mostra 1 slot de autoguardar (topo) +
/// até 30 slots manuais (baixo), em dois modos:
///
/// - <see cref="MenuMode.Save"/>: usado pelo SafeHaven (Refúgio Seguro). Mostra
///   o autoguardar (apenas pré-visualização, não clicável), todos os slots
///   manuais já usados (clicar = sobrescrever, com confirmação) e, enquanto
///   houver espaço, um botão "Criar Novo Save" (clicar = grava directamente
///   no próximo slot livre, sem confirmação).
/// - <see cref="MenuMode.Load"/>: usado pelo Menu de Pausa/Menu Principal.
///   Mostra o autoguardar e os slots manuais usados, todos clicáveis (com
///   confirmação) para carregar; "Criar Novo Save" nunca aparece.
///
/// Em ambos os modos, slots manuais usados podem ser apagados via o botão
/// "Apagar" de <see cref="SaveSlotButtonUI"/> (com confirmação) — ao apagar o
/// último dos 30, o botão "Criar Novo Save" reaparece (Rebuild é chamado de
/// novo).
///
/// Prefab esperado (montar no Editor, dentro de um Canvas):
/// - "panelRoot": GameObject raiz do menu (activado/desactivado em Open/Close).
/// - "slotContainer": Transform onde os SaveSlotButtonUI são instanciados
///   (normalmente com um Vertical Layout Group).
/// - "slotButtonPrefab": prefab de SaveSlotButtonUI.
/// - "confirmPanel"/"confirmText"/"confirmYesButton"/"confirmNoButton":
///   diálogo de confirmação genérico, reaproveitado para overwrite/load/apagar.
/// </summary>
public class SaveMenuController : MonoBehaviour
{
    /// <summary>Modo do menu: Guardar (a partir de um Refúgio Seguro) ou Carregar (Menu de Pausa/Principal).</summary>
    public enum MenuMode
    {
        Save,
        Load
    }

    [Header("Referências")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private Transform slotContainer;
    [SerializeField] private SaveSlotButtonUI slotButtonPrefab;
    [SerializeField] private TMP_Text titleText;

    [Header("Confirmação")]
    [SerializeField] private GameObject confirmPanel;
    [SerializeField] private TMP_Text confirmText;
    [SerializeField] private Button confirmYesButton;
    [SerializeField] private Button confirmNoButton;

    [Header("Textos")]
    [SerializeField] private string saveTitle = "Guardar Jogo";
    [SerializeField] private string loadTitle = "Carregar Jogo";
    [SerializeField] private string overwriteConfirmFormat = "Substituir o Save {0:00}?";
    [SerializeField] private string loadConfirmText = "Carregar este save? O progresso não guardado será perdido.";
    [SerializeField] private string deleteConfirmFormat = "Apagar o Save {0:00}? Esta acção não pode ser desfeita.";

    /// <summary>Disparado quando o menu fecha (por Close() ou depois de um load bem sucedido) — ex: para o PauseMenuController retomar o jogo.</summary>
    public event Action Closed;

    private readonly List<SaveSlotButtonUI> _spawned = new List<SaveSlotButtonUI>();
    private MenuMode _mode;
    private Action _pendingConfirmAction;

    private void Awake()
    {
        if (panelRoot != null) panelRoot.SetActive(false);
        if (confirmPanel != null) confirmPanel.SetActive(false);

        if (confirmYesButton != null) confirmYesButton.onClick.AddListener(OnConfirmYes);
        if (confirmNoButton != null) confirmNoButton.onClick.AddListener(OnConfirmNo);
    }

    // ---------------- Abrir / Fechar ----------------

    public void OpenForSave() => Open(MenuMode.Save);
    public void OpenForLoad() => Open(MenuMode.Load);

    public void Open(MenuMode mode)
    {
        _mode = mode;

        if (titleText != null) titleText.text = mode == MenuMode.Save ? saveTitle : loadTitle;
        if (panelRoot != null) panelRoot.SetActive(true);

        Rebuild();
    }

    public void Close()
    {
        HideConfirm();
        ClearSlots();

        if (panelRoot != null) panelRoot.SetActive(false);

        Closed?.Invoke();
    }

    // ---------------- Construção dos Slots ----------------

    private void Rebuild()
    {
        ClearSlots();

        var manager = SaveManager.Instance;
        if (manager == null || slotButtonPrefab == null || slotContainer == null) return;

        // Autoguardar (topo) — só clicável em modo Carregar e se existir.
        var autoData = manager.PeekSlot(-1, true);
        var autoBtn = SpawnSlotButton();
        bool autoInteractable = _mode == MenuMode.Load && autoData != null;
        autoBtn.SetupAuto(autoData, autoInteractable);

        // Slots manuais já usados.
        var used = manager.GetUsedManualSlots();
        foreach (int slotIndex in used)
        {
            var data = manager.PeekSlot(slotIndex, false);
            var btn = SpawnSlotButton();
            btn.SetupManual(slotIndex, data);
        }

        // "Criar Novo Save" — só em modo Guardar, enquanto houver slots livres.
        if (_mode == MenuMode.Save)
        {
            int free = manager.GetFirstFreeManualSlot();
            if (free >= 0)
            {
                var btn = SpawnSlotButton();
                btn.SetupCreateNew(free);
            }
        }

        SelectFirstInteractable();
    }

    private SaveSlotButtonUI SpawnSlotButton()
    {
        var btn = Instantiate(slotButtonPrefab, slotContainer);
        btn.gameObject.SetActive(true);
        btn.Clicked += OnSlotClicked;
        btn.DeleteClicked += OnDeleteClicked;
        _spawned.Add(btn);
        return btn;
    }

    private void ClearSlots()
    {
        foreach (var btn in _spawned)
        {
            if (btn == null) continue;
            btn.Clicked -= OnSlotClicked;
            btn.DeleteClicked -= OnDeleteClicked;
            Destroy(btn.gameObject);
        }

        _spawned.Clear();
    }

    private void SelectFirstInteractable()
    {
        if (EventSystem.current == null) return;

        EventSystem.current.SetSelectedGameObject(null);

        foreach (var btn in _spawned)
        {
            var button = btn.GetComponent<Button>();
            if (button != null && button.interactable)
            {
                EventSystem.current.SetSelectedGameObject(btn.gameObject);
                return;
            }
        }
    }

    // ---------------- Cliques nos Slots ----------------

    private void OnSlotClicked(SaveSlotButtonUI slot)
    {
        switch (slot.Kind)
        {
            case SaveSlotButtonUI.SlotKind.Auto:
                if (_mode == MenuMode.Load)
                    RequestConfirm(loadConfirmText, () => LoadSlot(-1, true));
                break;

            case SaveSlotButtonUI.SlotKind.Manual:
                if (_mode == MenuMode.Save)
                    RequestConfirm(string.Format(overwriteConfirmFormat, slot.SlotIndex + 1), () => SaveToSlot(slot.SlotIndex));
                else
                    RequestConfirm(loadConfirmText, () => LoadSlot(slot.SlotIndex, false));
                break;

            case SaveSlotButtonUI.SlotKind.CreateNew:
                // Slot vazio: grava directamente, sem confirmação.
                SaveToSlot(slot.SlotIndex);
                break;
        }
    }

    private void OnDeleteClicked(SaveSlotButtonUI slot)
    {
        if (slot.Kind != SaveSlotButtonUI.SlotKind.Manual) return;

        int slotIndex = slot.SlotIndex;
        RequestConfirm(string.Format(deleteConfirmFormat, slotIndex + 1), () =>
        {
            SaveManager.Instance?.DeleteManualSlot(slotIndex);
            Rebuild();
        });
    }

    // ---------------- Acções ----------------

    private void SaveToSlot(int slotIndex)
    {
        SaveManager.Instance?.SaveToManualSlot(slotIndex);
        Rebuild();
    }

    private void LoadSlot(int slotIndex, bool isAuto)
    {
        var data = SaveManager.Instance?.PeekSlot(slotIndex, isAuto);
        if (data == null) return;

        StartCoroutine(LoadRoutine(slotIndex, isAuto, data));
    }

    private IEnumerator LoadRoutine(int slotIndex, bool isAuto, SaveData data)
    {
        Close();

        // Tarefa #16 (tela de loading): se o save pertence a outra cena, a
        // troca passa pelo overlay de loading (LoadingScreenController) — o
        // save só é aplicado depois da nova cena activar, ainda com o overlay
        // visível.
        if (!string.IsNullOrEmpty(data.sceneName) && SceneManager.GetActiveScene().name != data.sceneName)
        {
            bool done = false;
            LoadingScreenController.Instance.LoadScene(data.sceneName, () =>
            {
                ApplyLoadedSave(slotIndex, isAuto);
                done = true;
            });

            while (!done) yield return null;
        }
        else
        {
            ApplyLoadedSave(slotIndex, isAuto);
        }
    }

    private void ApplyLoadedSave(int slotIndex, bool isAuto)
    {
        if (isAuto) SaveManager.Instance?.LoadAutosave();
        else SaveManager.Instance?.LoadManualSlot(slotIndex);
    }

    // ---------------- Confirmação ----------------

    private void RequestConfirm(string message, Action onYes)
    {
        if (confirmPanel == null)
        {
            // Sem painel de confirmação configurado: executa directamente.
            onYes?.Invoke();
            return;
        }

        _pendingConfirmAction = onYes;
        if (confirmText != null) confirmText.text = message;
        confirmPanel.SetActive(true);

        if (EventSystem.current != null && confirmYesButton != null)
            EventSystem.current.SetSelectedGameObject(confirmYesButton.gameObject);
    }

    private void OnConfirmYes()
    {
        var action = _pendingConfirmAction;
        HideConfirm();
        action?.Invoke();
    }

    private void OnConfirmNo() => HideConfirm();

    private void HideConfirm()
    {
        _pendingConfirmAction = null;
        if (confirmPanel != null) confirmPanel.SetActive(false);
    }
}
